const item = $input.first();
const body = item.json.body || item.json || {};
const binary = item.binary || {};

const questionFile = binary.question_file;
const answerFile = binary.answer_file;

if (!questionFile || !answerFile) {
  throw new Error('Thieu file question_file hoac answer_file. Gui multipart/form-data tu API backend.');
}

const examId = Number(body.exam_id);
if (!Number.isInteger(examId) || examId <= 0) {
  throw new Error('exam_id khong hop le. Workflow upload_exam yeu cau exam_id tu database hien tai.');
}

const examCode = String(body.exam_code || '').trim();
if (!examCode) {
  throw new Error('Thieu exam_code.');
}

const title = String(body.title || '').trim();
if (!title) {
  throw new Error('Thieu title de thi.');
}

const answerName = String(answerFile.fileName || answerFile.filename || '').toLowerCase();
const answerMime = String(answerFile.mimeType || answerFile.mimetype || '').toLowerCase();
const supportedExtensions = ['.pdf', '.png', '.jpg', '.jpeg', '.webp', '.doc', '.docx'];
const hasSupportedExtension = supportedExtensions.some((extension) => answerName.endsWith(extension));
const supportedMimeTypes = [
  'application/pdf',
  'image/png',
  'image/jpeg',
  'image/webp',
  'application/msword',
  'application/vnd.openxmlformats-officedocument.wordprocessingml.document'
];

if (!hasSupportedExtension && !supportedMimeTypes.includes(answerMime)) {
  throw new Error('answer_file khong thuoc dinh dang OCR duoc ho tro.');
}

const teacherId = Number(body.teacher_id);

return [{
  json: {
    exam_id: examId,
    exam_code: examCode,
    title,
    description: String(body.description || '').trim(),
    class_code: String(body.class_code || '').trim(),
    subject_code: String(body.subject_code || '').trim(),
    subject_name: String(body.subject_name || '').trim(),
    exam_type: String(body.exam_type || '').trim(),
    exam_round: String(body.exam_round || '').trim(),
    teacher_id: Number.isInteger(teacherId) && teacherId > 0 ? teacherId : null,
    question_filename: String(questionFile.fileName || questionFile.filename || ''),
    answer_filename: String(answerFile.fileName || answerFile.filename || '')
  },
  binary: {
    question_file: questionFile,
    answer_file: answerFile
  }
}];

const meta = $('Validate API payload').first();
const upload = $input.first();
const questionFilePath = upload.json.webViewLink || upload.json.webContentLink || upload.json.id || '';
if (!questionFilePath) {
  throw new Error('Khong lay duoc URL Google Drive cho question_file');
}
return [{ json: { ...meta.json, question_file_path: questionFilePath, question_drive_file_id: upload.json.id || null }, binary: { ...meta.binary } }];

const meta = $('Restore payload after question upload').first().json;
const binary = $('Validate API payload').first().binary || {};
const answerUpload = $input.first();
const answerFilePath = answerUpload.json.webViewLink || answerUpload.json.webContentLink || answerUpload.json.id || '';
if (!answerFilePath) {
  throw new Error('Khong lay duoc URL Google Drive cho answer_file');
}
return [{ json: { ...meta, answer_file_path: answerFilePath, answer_drive_file_id: answerUpload.json.id || null }, binary: { ...binary } }];

const meta = $('Attach Drive uploads').first().json;
const ocr = $('Edit Fields').first().json;
return [{ json: { ...meta, markdown: ocr.markdown || '', page_count: Number(ocr.page_count || 0) } }];

const rawText = String($input.first().json.text || '').trim();
if (!rawText) {
  throw new Error('Model khong tra ve noi dung extract JSON.');
}
let parsed;
try {
  parsed = JSON.parse(rawText);
} catch (error) {
  throw new Error(`Khong parse duoc JSON extract tu model: ${error.message}`);
}
if (Array.isArray(parsed)) {
  parsed = { questions: parsed };
}
if (!parsed || typeof parsed !== 'object') {
  throw new Error('Output extract khong dung dinh dang object.');
}
const rawQuestions = Array.isArray(parsed.questions) ? parsed.questions : [];
const normalizedQuestions = rawQuestions.map((question, index) => {
  const questionText = String(question.question_text || '').trim();
  const expectedAnswer = String(question.expected_answer || '').trim();
  const questionNo = String(question.question_no || index + 1).trim();
  const options = Array.isArray(question.options) ? question.options.map(option => String(option || '').trim()).filter(Boolean) : [];
  const rubrics = Array.isArray(question.rubrics) ? question.rubrics.map((rubric) => {
    const key = String(rubric?.key || rubric?.content || '').trim();
    const score = Number(rubric?.score);
    return { key, score: Number.isFinite(score) && score >= 0 ? score : null };
  }).filter((rubric) => rubric.key) : [];
  const rawMaxScore = Number(question.max_score);
  const questionType = String(question.question_type || (options.length ? 'multiple_choice' : 'essay')).trim() || 'unknown';
  const defaultScore = questionType === 'multiple_choice' ? 1 : 2;
  return {
    question_no: questionNo || String(index + 1),
    question_text: questionText,
    question_type: questionType,
    options,
    expected_answer: expectedAnswer,
    rubrics,
    max_score: Number.isFinite(rawMaxScore) && rawMaxScore > 0 ? rawMaxScore : defaultScore
  };
}).filter((question) => question.question_text || question.expected_answer || question.options.length || question.rubrics.length);
const computedTotalMaxScore = normalizedQuestions.reduce((sum, question) => sum + Number(question.max_score || 0), 0);
const rawTotalMaxScore = Number(parsed.total_max_score);
return [{ json: { extract_json: { questions: normalizedQuestions, total_max_score: Number.isFinite(rawTotalMaxScore) && rawTotalMaxScore > 0 ? rawTotalMaxScore : normalizedQuestions.length ? Number(computedTotalMaxScore.toFixed(2)) : null }, questions_count: normalizedQuestions.length } }];

const meta = $('Restore extracted markdown').first().json;
const extract = $('exam_detail').first().json.extract_json;
const questionsCount = Number($('exam_detail').first().json.questions_count || 0);
const executionId = $execution.id;
function escapeLiteral(value) { return String(value ?? '').replace(/'/g, "''"); }
function sqlText(value) { const text = String(value ?? '').trim(); return text ? `'${escapeLiteral(text)}'` : 'NULL'; }
function sqlNumber(value) { const number = Number(value); return Number.isFinite(number) ? String(number) : 'NULL'; }
function sqlJson(value) { if (value === undefined || value === null) { return 'NULL'; } return `'${escapeLiteral(JSON.stringify(value))}'::jsonb`; }
const payload = { exam_code: meta.exam_code, title: meta.title, question_file_path: meta.question_file_path, answer_file_path: meta.answer_file_path, questions_count: questionsCount, answer_extract_file_path: extract };
const sql = `
UPDATE exams
SET
  status = 'ready',
  question_file_path = ${sqlText(meta.question_file_path)},
  answer_file_path = ${sqlText(meta.answer_file_path)},
  answer_extract_file_path = ${sqlJson(extract)},
  updated_at = NOW(),
  updated_by = ${sqlNumber(meta.teacher_id)}
WHERE id = ${sqlNumber(meta.exam_id)};

INSERT INTO system_logs (
  log_type,
  ref_table,
  ref_id,
  exam_id,
  class_code,
  workflow_execution_id,
  model_name,
  status,
  message,
  response_payload,
  created_at,
  created_by,
  updated_by
) VALUES (
  'exam_extract',
  'exams',
  ${sqlNumber(meta.exam_id)},
  ${sqlNumber(meta.exam_id)},
  ${sqlText(meta.class_code)},
  ${sqlText(executionId)},
  'google-drive + mistral-ocr-latest + gpt-4.1-mini',
  'success',
  ${sqlText(`Extract dap an thanh cong voi ${questionsCount} cau hoi.`)},
  ${sqlJson(payload)},
  NOW(),
  ${sqlNumber(meta.teacher_id)},
  ${sqlNumber(meta.teacher_id)}
);`;
return [{ json: { exam_id: meta.exam_id, exam_code: meta.exam_code, question_file_path: meta.question_file_path, answer_file_path: meta.answer_file_path, answer_extract_file_path: extract, questions_count: questionsCount, sql } }];
